private Integer getBasicRow(final int col) {
    Integer row = null;
    double threshold = 1e-10; // Define a threshold for numerical tolerance
    for (int i = getNumObjectiveFunctions(); i < getHeight(); i++) {
        double entry = getEntry(i, col);
        if (Math.abs(entry - 1.0) < epsilon) { // Check for entry being approximately one
            if (row == null) {
                row = i;
            } else {
                return null; // More than one entry is approximately one
            }
        } else if (Math.abs(entry) > threshold) { // Allow small noise
            return null; // Entry is not approximately zero
        }
    }
    return row;
}

